export const handle = async (request, response) => {
    // Accedemos a la ruta que confirmamos funciona
    let polizas = (request.inputs && request.inputs.Polizas) ? request.inputs.Polizas : 
                  (request.data && request.data.inputs && request.data.inputs.Polizas) ? request.data.inputs.Polizas : [];

    let infoAgente = "";

    if (Array.isArray(polizas) && polizas.length > 0) {
        polizas.forEach(p => {
            // Formateamos la fecha para que solo se vea YYYY-MM-DD
            let fechaVenc = p.cr555_vencimiento ? p.cr555_vencimiento.substring(0, 10) : "N/A";

            infoAgente += "Póliza: " + (p.cr555_newcolumn || "N/A") + 
                          "|" + (p.cr555_tipo || "N/A") + 
                          "|Vig:" + fechaVenc + "\n";
        });
    } else {
        infoAgente = "El cliente no cuenta con pólizas activas.";
    }

    response.data = { 'AgentPolizaInfo': infoAgente };
    return response;
};
